"""
Auto-generated bytecode loader
Run: python this_file.py
"""

import sys
import zlib
import marshal
import base64


# Encrypted data
ENCRYPTED = ""

def main():
    try:
        print("[✓] Loading encrypted module...", file=sys.stderr)
        
        # Base64 decode
        compressed = base64.b64decode(ENCRYPTED)
        print(f"[✓] Decoded: {len(compressed)} bytes", file=sys.stderr)
        
        
        
        # Decompress
        try:
            marshalled = zlib.decompress(compressed)
            print(f"[✓] Decompressed: {len(marshalled)} bytes", file=sys.stderr)
        except Exception as e:
            print(f"[✗] Decompress failed: {e}", file=sys.stderr)
            sys.exit(1)
        
        # Load marshal
        try:
            code_obj = marshal.loads(marshalled)
            print(f"[✓] Code object loaded: {type(code_obj)}", file=sys.stderr)
        except Exception as e:
            print(f"[✗] Marshal load failed: {e}", file=sys.stderr)
            sys.exit(1)
        
        # Execute
        print("[✓] Executing code...", file=sys.stderr)
        print("-" * 40)
        
        # Create namespace
        namespace = {'__name__': '__main__', '__file__': 'main3.py'}
        
        # Execute
        exec(code_obj, namespace)
        
    except Exception as e:
        print(f"\n[✗] Execution failed: {e}", file=sys.stderr)
        import traceback
        traceback.print_exc()
        sys.exit(1)

if __name__ == "__main__":
    main()
